# Generated by openai (gpt-5.4)
# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import os
import uuid
import threading
import numpy as np
import pandas as pd
import tensorflow as tf
from werkzeug.utils import secure_filename

app = Flask(__name__)

BASE_DIR = os.path.abspath(os.path.dirname(__file__))
UPLOAD_DIR = os.path.join(BASE_DIR, "uploads")
MODEL_DIR = os.path.join(BASE_DIR, "model_store")
os.makedirs(UPLOAD_DIR, exist_ok=True)
os.makedirs(MODEL_DIR, exist_ok=True)

ALLOWED_EXTENSIONS = {"csv"}
IMAGE_SIZE = (64, 64)
BATCH_SIZE = 32
EPOCHS = 5
NUM_CLASSES = 2

model_lock = threading.Lock()
training_lock = threading.Lock()
current_model = None
class_names = None

def allowed_file(filename):
    return "." in filename and filename.rsplit(".", 1)[1].lower() in ALLOWED_EXTENSIONS

def build_model(num_classes):
    model = tf.keras.Sequential([
        tf.keras.layers.Input(shape=(IMAGE_SIZE[0], IMAGE_SIZE[1], 3)),
        tf.keras.layers.Rescaling(1.0 / 255),
        tf.keras.layers.Conv2D(32, 3, activation="relu"),
        tf.keras.layers.MaxPooling2D(),
        tf.keras.layers.Conv2D(64, 3, activation="relu"),
        tf.keras.layers.MaxPooling2D(),
        tf.keras.layers.Conv2D(128, 3, activation="relu"),
        tf.keras.layers.GlobalAveragePooling2D(),
        tf.keras.layers.Dense(128, activation="relu"),
        tf.keras.layers.Dense(num_classes, activation="softmax")
    ])
    model.compile(
        optimizer="adam",
        loss="sparse_categorical_crossentropy",
        metrics=["accuracy"]
    )
    return model

def decode_image_bytes(image_bytes):
    image = tf.io.decode_image(image_bytes, channels=3, expand_animations=False)
    image = tf.image.resize(image, IMAGE_SIZE)
    image = tf.cast(image, tf.float32)
    return image.numpy()

def load_csv_dataset(csv_path):
    df = pd.read_csv(csv_path)
    required_columns = {"image_path", "label"}
    if not required_columns.issubset(df.columns):
        raise ValueError("CSV must contain columns: image_path,label")

    labels = sorted(df["label"].astype(str).unique().tolist())
    label_to_index = {label: idx for idx, label in enumerate(labels)}

    images = []
    y = []

    csv_dir = os.path.dirname(csv_path)
    for _, row in df.iterrows():
        image_path = str(row["image_path"])
        label = str(row["label"])
        full_path = image_path if os.path.isabs(image_path) else os.path.join(csv_dir, image_path)
        if not os.path.exists(full_path):
            continue
        with open(full_path, "rb") as f:
            image = decode_image_bytes(f.read())
        images.append(image)
        y.append(label_to_index[label])

    if not images:
        raise ValueError("No valid images found in dataset")

    x = np.array(images, dtype=np.float32)
    y = np.array(y, dtype=np.int32)
    return x, y, labels

def save_model(model, labels):
    model_path = os.path.join(MODEL_DIR, "community_model.keras")
    labels_path = os.path.join(MODEL_DIR, "labels.txt")
    model.save(model_path)
    with open(labels_path, "w", encoding="utf-8") as f:
        for label in labels:
            f.write(f"{label}\n")

def load_model_if_exists():
    global current_model, class_names
    model_path = os.path.join(MODEL_DIR, "community_model.keras")
    labels_path = os.path.join(MODEL_DIR, "labels.txt")
    if os.path.exists(model_path) and os.path.exists(labels_path):
        current_model = tf.keras.models.load_model(model_path)
        with open(labels_path, "r", encoding="utf-8") as f:
            class_names = [line.strip() for line in f if line.strip()]

def retrain_from_all_csvs():
    global current_model, class_names
    with training_lock:
        csv_files = []
        for root, _, files in os.walk(UPLOAD_DIR):
            for file in files:
                if file.lower().endswith(".csv"):
                    csv_files.append(os.path.join(root, file))

        if not csv_files:
            return

        all_images = []
        all_labels = []
        all_label_names = set()

        datasets = []
        for csv_file in csv_files:
            df = pd.read_csv(csv_file)
            if {"image_path", "label"}.issubset(df.columns):
                all_label_names.update(df["label"].astype(str).unique().tolist())
                datasets.append(df)

        if not datasets or not all_label_names:
            return

        labels = sorted(list(all_label_names))
        label_to_index = {label: idx for idx, label in enumerate(labels)}

        for csv_file in csv_files:
            df = pd.read_csv(csv_file)
            if not {"image_path", "label"}.issubset(df.columns):
                continue
            csv_dir = os.path.dirname(csv_file)
            for _, row in df.iterrows():
                image_path = str(row["image_path"])
                label = str(row["label"])
                full_path = image_path if os.path.isabs(image_path) else os.path.join(csv_dir, image_path)
                if not os.path.exists(full_path):
                    continue
                try:
                    with open(full_path, "rb") as f:
                        image = decode_image_bytes(f.read())
                    all_images.append(image)
                    all_labels.append(label_to_index[label])
                except Exception:
                    continue

        if not all_images:
            return

        x = np.array(all_images, dtype=np.float32)
        y = np.array(all_labels, dtype=np.int32)

        model = build_model(len(labels))
        model.fit(x, y, batch_size=BATCH_SIZE, epochs=EPOCHS, validation_split=0.2, verbose=0)

        with model_lock:
            current_model = model
            class_names = labels
            save_model(current_model, class_names)

@app.route("/upload-dataset", methods=["POST"])
def upload_dataset():
    if "file" not in request.files:
        return jsonify({"error": "Missing file"}), 400

    file = request.files["file"]
    if file.filename == "":
        return jsonify({"error": "Empty filename"}), 400

    if not allowed_file(file.filename):
        return jsonify({"error": "Only CSV files are allowed"}), 400

    dataset_id = str(uuid.uuid4())
    dataset_dir = os.path.join(UPLOAD_DIR, dataset_id)
    os.makedirs(dataset_dir, exist_ok=True)

    filename = secure_filename(file.filename)
    csv_path = os.path.join(dataset_dir, filename)
    file.save(csv_path)

    threading.Thread(target=retrain_from_all_csvs, daemon=True).start()

    return jsonify({
        "message": "Dataset uploaded successfully",
        "dataset_id": dataset_id,
        "csv_path": csv_path
    })

@app.route("/contribute-example", methods=["POST"])
def contribute_example():
    if "image" not in request.files or "label" not in request.form:
        return jsonify({"error": "Provide image file and label"}), 400

    image_file = request.files["image"]
    label = request.form["label"].strip()

    if image_file.filename == "" or not label:
        return jsonify({"error": "Invalid image or label"}), 400

    contribution_id = str(uuid.uuid4())
    contribution_dir = os.path.join(UPLOAD_DIR, "contributions", contribution_id)
    os.makedirs(contribution_dir, exist_ok=True)

    image_filename = secure_filename(image_file.filename)
    image_path = os.path.join(contribution_dir, image_filename)
    image_file.save(image_path)

    csv_path = os.path.join(contribution_dir, "contribution.csv")
    pd.DataFrame([{
        "image_path": image_filename,
        "label": label
    }]).to_csv(csv_path, index=False)

    threading.Thread(target=retrain_from_all_csvs, daemon=True).start()

    return jsonify({
        "message": "Training example contributed successfully",
        "contribution_id": contribution_id
    })

@app.route("/predict", methods=["POST"])
def predict():
    global current_model, class_names
    if "image" not in request.files:
        return jsonify({"error": "Missing image file"}), 400

    with model_lock:
        if current_model is None or not class_names:
            return jsonify({"error": "Model not trained yet"}), 400

        image_file = request.files["image"]
        image_bytes = image_file.read()
        image = decode_image_bytes(image_bytes)
        x = np.expand_dims(image, axis=0)
        preds = current_model.predict(x, verbose=0)[0]
        pred_idx = int(np.argmax(preds))
        confidence = float(preds[pred_idx])
        label = class_names[pred_idx]

    return jsonify({
        "predicted_label": label,
        "confidence": confidence,
        "scores": {class_names[i]: float(preds[i]) for i in range(len(class_names))}
    })

@app.route("/status", methods=["GET"])
def status():
    with model_lock:
        return jsonify({
            "model_loaded": current_model is not None,
            "classes": class_names or []
        })

if __name__ == "__main__":
    load_model_if_exists()
    app.run(host="0.0.0.0", port=5000)